      },
      {
        id: 'TICKET-003',
        priority: 'medium',
        issue: 'Feature X not working as described',
        userEnvironment: 'MacOS 13.1, latest app version',
        attempts: ['Checked docs', 'Restarted app'],
      },
    ];

    for (const ticket of tickets) {
      console.log(
        `┌─ ${ticket.id} [${ticket.priority.toUpperCase()}] ${'─'.repeat(40)}`
      );
